class Solution:
    def kidsWithCandies(self, candies, extraCandies):
        result = []
        for i in range(len(candies)):
            best = max(candies[j] for j in range(len(candies)) if j != i)
            result.append(candies[i] + extraCandies >= best or candies[i] + extraCandies >= candies[i])
        # simpler: just check against global max
        mx = max(candies)
        return [c + extraCandies >= mx for c in candies]

